using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 – Discriminator property renamed to "$type" in EF9.
            // Preserve "Discriminator" so existing 500K documents and raw SQL
            // queries (c.Discriminator = 'Product') continue to work.
            b.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // BREAKING CHANGE 2 – HasIndex() now throws for the Cosmos provider.
            // Cosmos indexing is managed via the container's indexing policy in
            // the Azure portal or ARM/Bicep templates, not through EF model config.
            // Removed: b.HasIndex(p => p.Sku);

            // BREAKING CHANGE 3 – id synthesis changed from "EntityType|Key"
            // (e.g. "Product|123") to the raw key value ("123"). Map the explicit
            // CosmosId property to the JSON "id" field to preserve the old format.
            b.Property(p => p.CosmosId).ToJsonProperty("id");
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }

    // Preserves EF Core 8 id format "Product|{key}" for backward compatibility.
    // New entities compute the value from Id; loaded entities use the stored value.
    private string _cosmosId;
    public string CosmosId
    {
        get => _cosmosId ??= $"Product|{Id}";
        set => _cosmosId = value;
    }
}

