class CosmosQuery
{
    // BREAKING CHANGE 4 – Cosmos provider removed synchronous query execution
    // in EF9. All queries must use async APIs (ToListAsync, FirstAsync, etc.).
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — works because "Discriminator" property name is preserved
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

